    const typeFilter =        document.getElementById('typeFilter');    const rows =        document.querySelectorAll('.vehicle-row');    const cards =        document.querySelectorAll('.vehicle-card-filter');    function applyFilters() {        const search =            searchInput.value.toLowerCase();        const operational =            operationalFilter.value;        const status =            statusFilter.value;        const type =            typeFilter.value;        rows.forEach(row => {            const searchable =                `                    ${row.dataset.name}                    ${row.dataset.plate}                    ${row.dataset.brand}                    ${row.dataset.model}                    ${row.dataset.year}                `;            const matchSearch =                searchable.includes(search);            const matchOperational =                !operational ||                row.dataset.operational === operational;            const matchStatus =                !status ||                row.dataset.status === status;            const matchType =                !type ||                row.dataset.type === type;            const visible =                matchSearch &&                matchOperational &&                matchStatus &&                matchType;            row.style.display =                visible                    ? ''                    : 'none';        });        cards.forEach(card => {            const searchable =                `                    ${card.dataset.name}                    ${card.dataset.plate}                    ${card.dataset.brand}                    ${card.dataset.model}                    ${card.dataset.year}                `;            const matchSearch =                searchable.includes(search);            const matchOperational =                !operational ||                card.dataset.operational === operational;            const matchStatus =                !status ||                card.dataset.status === status;            const matchType =                !type ||                card.dataset.type === type;            const visible =                matchSearch &&                matchOperational &&                matchStatus &&                matchType;            card.style.display =                visible                    ? ''                    : 'none';        });    }    searchInput.addEventListener(        'input',        applyFilters    );    operationalFilter.addEventListener(        'change',        applyFilters    );    statusFilter.addEventListener(        'change',        applyFilters    );    typeFilter.addEventListener(        'change',        applyFilters    );});</script>@endsection